 18→void ULFPShopWidget::Setup(ULFPGameInstance* GI, FName InShopID, const FLFPShopDefinition& InShopDefinition)
 19→{
 20→	CachedGameInstance = GI;
 21→	CachedShopID = InShopID;
 22→	CachedShopDefinition = InShopDefinition;
 23→	SelectedRelicIndex = CachedShopDefinition.RelicList.Num() > 0 ? 0 : INDEX_NONE;
 24→	RefreshShopUI();
 25→}
 26→
 27→void ULFPShopWidget::RefreshShopUI()
 28→{
 29→	if (Text_Title)
 30→	{
 31→		Text_Title->SetText(CachedShopDefinition.DisplayName.IsEmpty() ? FText::FromString(TEXT("遗物商店")) : CachedShopDefinition.DisplayName);
 32→	}
 33→
 34→	if (Text_Gold && CachedGameInstance)
 35→	{
 36→		Text_Gold->SetText(FText::FromString(FString::Printf(TEXT("金币: %d"), CachedGameInstance->GetGold())));
 37→	}
 38→
 39→	RefreshRelicList();
 40→	RefreshDetailPanel();
 41→}
 42→
 43→void ULFPShopWidget::RefreshRelicList()
 44→{
 45→	RelicButtons.Empty();
 46→	ButtonToRelicIndexMap.Empty();
 47→
 48→	if (Box_RelicList)
 49→	{
 50→		Box_RelicList->ClearChildren();
 51→	}
 52→
 53→	if (!CachedGameInstance || !Box_RelicList)
 54→	{
 55→		return;
 56→	}
 57→
 58→	for (int32 i = 0; i < CachedShopDefinition.RelicList.Num(); ++i)
 59→	{
 60→		const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[i];
 61→		FLFPRelicDefinition RelicDefinition;
 62→		if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, RelicDefinition))
 63→		{
 64→			continue;
 65→		}
 66→
 67→		UButton* RelicButton = NewObject<UButton>(this);
 68→		if (!RelicButton)
 69→		{
 70→			continue;
 71→		}
 72→
 73→		UTextBlock* Label = NewObject<UTextBlock>(RelicButton);
 74→		if (Label)
 75→		{
 76→			FString Suffix;
 77→			if (CachedGameInstance->HasRelic(Entry.RelicID))
 78→			{
 79→				Suffix = TEXT(" [已拥有]");
 80→			}
 81→			else if (!CachedGameInstance->CanAffordGold(Entry.Price))
 82→			{
 83→				Suffix = TEXT(" [金币不足]");
 84→			}
 85→
 86→			Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *RelicDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
 87→			RelicButton->AddChild(Label);
 88→		}
 89→
 90→		UVerticalBoxSlot* ItemSlot = Box_RelicList->AddChildToVerticalBox(RelicButton);
 91→		if (ItemSlot)
 92→		{
 93→			ItemSlot->SetPadding(FMargin(4.f));
 94→		}
 95→
 96→		RelicButton->OnClicked.AddDynamic(this, &ULFPShopWidget::OnRelicButtonClicked);
 97→		RelicButtons.Add(RelicButton);
 98→		ButtonToRelicIndexMap.Add(RelicButton, i);
 99→	}
100→}
101→
102→void ULFPShopWidget::RefreshDetailPanel()
103→{
104→	if (!CachedGameInstance)
105→	{
106→		return;
107→	}
108→
109→	if (!CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
110→	{
111→		if (Text_SelectedName) Text_SelectedName->SetText(FText::FromString(TEXT("未选择遗物")));
112→		if (Text_SelectedDescription) Text_SelectedDescription->SetText(FText::GetEmpty());
113→		if (Text_SelectedPrice) Text_SelectedPrice->SetText(FText::GetEmpty());
114→		if (Text_Status) Text_Status->SetText(FText::GetEmpty());
115→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
116→		if (Image_SelectedRelic) Image_SelectedRelic->SetBrushFromTexture(nullptr);
117→		return;
118→	}
119→
120→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
121→	FLFPRelicDefinition Definition;
122→	if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, Definition))
123→	{
124→		if (Text_Status) Text_Status->SetText(FText::FromString(TEXT("遗物定义缺失")));
125→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
126→		return;
127→	}
128→
129→	if (Image_SelectedRelic)
130→	{
131→		Image_SelectedRelic->SetBrushFromTexture(Definition.Icon);
132→	}
133→	if (Text_SelectedName)
134→	{
135→		Text_SelectedName->SetText(Definition.DisplayName);
136→	}
137→	if (Text_SelectedDescription)
138→	{
139→		Text_SelectedDescription->SetText(FText::FromString(FString::Printf(TEXT("%s\n%s"), *Definition.Description.ToString(), *BuildEffectDescription(Definition))));
140→	}
141→	if (Text_SelectedPrice)
142→	{
143→		Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
144→	}
145→
146→	bool bOwned = CachedGameInstance->HasRelic(Entry.RelicID);
147→	bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
148→	if (Button_Purchase)
149→	{
150→		Button_Purchase->SetIsEnabled(!bOwned && bCanAfford);
151→	}
152→	if (Text_Status)
153→	{
154→		if (bOwned)
155→		{
156→			Text_Status->SetText(FText::FromString(TEXT("已拥有")));
157→		}
158→		else if (!bCanAfford)
159→		{
160→			Text_Status->SetText(FText::FromString(TEXT("金币不足")));
161→		}
162→		else
163→		{
164→			Text_Status->SetText(FText::FromString(TEXT("可购买")));
165→		}
166→	}
167→}
168→
169→FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
170→{
171→	TArray<FString> Parts;
172→	for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
173→	{
174→		switch (Effect.EffectType)
175→		{
176→		case ELFPRelicEffectType::RET_MaxHealthFlat:
177→			Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
178→			break;
179→		case ELFPRelicEffectType::RET_AttackFlat:
180→			Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
181→			break;
182→		case ELFPRelicEffectType::RET_DefenseFlat:
183→			Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
184→			break;
185→		case ELFPRelicEffectType::RET_SpeedFlat:
186→			Parts.Add(FString::Printf(TEXT("速度 %+d"), Effect.Value));
187→			break;
188→		default:
189→			break;
190→		}
191→	}
192→
193→	return Parts.Num() > 0 ? FString::Join(Parts, TEXT("\n")) : TEXT("无效果");
194→}
