196→void ULFPShopWidget::OnRelicButtonClicked()
197→{
198→	for (const auto& Pair : ButtonToRelicIndexMap)
199→	{
200→		if (Pair.Key && Pair.Key->IsHovered())
201→		{
202→			SelectedRelicIndex = Pair.Value;
203→			RefreshDetailPanel();
204→			return;
205→		}
206→	}
207→}
208→
209→void ULFPShopWidget::OnPurchaseClicked()
210→{
211→	if (!CachedGameInstance || !CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
212→	{
213→		return;
214→	}
215→
216→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
217→	if (CachedGameInstance->TryPurchaseRelic(Entry.RelicID, Entry.Price))
218→	{
219→		RefreshShopUI();
220→	}
221→}
222→
223→void ULFPShopWidget::OnCloseClicked()
224→{
225→	SetVisibility(ESlateVisibility::Collapsed);
226→	RemoveFromParent();
227→	OnClosed.Broadcast();
228→}
