128→void ALFPWorldMapGameMode::ProcessCapturedUnits(const TArray<FLFPUnitEntry>& CapturedUnits)
129→{
130→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
131→	if (!GI) return;
132→
133→	for (const FLFPUnitEntry& Unit : CapturedUnits)
134→	{
135→		if (!GI->TryAddUnit(Unit))
136→		{
137→			// 队伍和备战营都满了，加入待处理队列
138→			PendingCapturedUnits.Add(Unit);
139→		}
140→	}
141→
142→	// 有待处理的，显示替换 UI
143→	if (PendingCapturedUnits.Num() > 0)
144→	{
145→		ShowNextReplacementUI();
146→	}
147→}
148→
149→void ALFPWorldMapGameMode::ShowNextReplacementUI()
150→{
151→	if (PendingCapturedUnits.Num() == 0) return;
152→
153→	FLFPUnitEntry NextUnit = PendingCapturedUnits[0];
154→	PendingCapturedUnits.RemoveAt(0);
155→
156→	if (!ReplacementWidgetClass)
157→	{
158→		UE_LOG(LogTemp, Warning, TEXT("ReplacementWidgetClass 未配置，放弃单位 %s"), *NextUnit.TypeID.ToString());
159→		ShowNextReplacementUI();
160→		return;
161→	}
162→
163→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
164→	if (!GI) return;
165→
166→	APlayerController* PC = GetWorld()->GetFirstPlayerController();
167→	if (!PC) return;
168→
169→	if (!ReplacementWidget)
170→	{
171→		ReplacementWidget = CreateWidget<ULFPUnitReplacementWidget>(PC, ReplacementWidgetClass);
172→	}
173→
174→	if (ReplacementWidget)
175→	{
176→		ReplacementWidget->Setup(NextUnit, GI->PartyUnits, GI->ReserveUnits, GI->UnitRegistry);
177→		ReplacementWidget->OnReplacementComplete.AddDynamic(this, &ALFPWorldMapGameMode::OnReplacementComplete);
178→		ReplacementWidget->AddToViewport(100);
179→	}
180→}

