 62→bool ALFPTacticsUnit::InitializeFromRegistry(ULFPUnitRegistryDataAsset* Registry)
 63→{
 64→    if (bStatsInitialized)
 65→    {
 66→        return true;
 67→    }
 68→
 69→    if (!Registry || UnitTypeID == NAME_None)
 70→    {
 71→        return false;
 72→    }
 73→
 74→    FLFPUnitRegistryEntry Entry;
 75→    if (!Registry->FindEntry(UnitTypeID, Entry))
 76→    {
 77→        return false;
 78→    }
 79→
 80→    ApplyRegistryEntry(Entry);
 81→    bStatsInitialized = true;
 82→    return true;
 83→}
