105→void ALFPTacticsUnit::ResetCurrentStatsToBase(bool bResetHealth)
106→{
107→    CurrentAttackType = BaseAttackType;
108→    CurrentAttack = BaseAttack;
109→    CurrentMaxHealth = BaseMaxHealth;
110→    CurrentMaxMovePoints = BaseMaxMovePoints;
111→    CurrentSpeed = BaseSpeed;
112→    CurrentAttackCount = BaseAttackCount;
113→    CurrentActionCount = BaseActionCount;
114→    CurrentPhysicalBlock = BasePhysicalBlock;
115→    CurrentSpellDefense = BaseSpellDefense;
116→    CurrentWeight = BaseWeight;
117→
118→    AttackPower = CurrentAttack;
119→    MaxHealth = CurrentMaxHealth;
120→    MaxMovePoints = CurrentMaxMovePoints;
121→    Speed = CurrentSpeed;
122→    Defense = CurrentPhysicalBlock;
123→
124→    if (bResetHealth)
125→    {
126→        CurrentHealth = CurrentMaxHealth;
127→    }
128→    else
129→    {
130→        CurrentHealth = FMath::Clamp(CurrentHealth, 0, CurrentMaxHealth);
131→    }
132→
133→    CurrentMovePoints = CurrentMaxMovePoints;
134→}
