139→    AttackPower = CurrentAttack;
140→}
141→
142→void ALFPTacticsUnit::AddCurrentMaxHealth(int32 Delta, bool bKeepHealthRatio)
143→{
144→    const int32 OldMaxHealth = CurrentMaxHealth;
145→    CurrentMaxHealth = FMath::Max(1, CurrentMaxHealth + Delta);
146→    MaxHealth = CurrentMaxHealth;
147→
148→    if (bKeepHealthRatio && OldMaxHealth > 0)
149→    {
150→        const float HealthRatio = static_cast<float>(CurrentHealth) / OldMaxHealth;
151→        CurrentHealth = FMath::Clamp(FMath::RoundToInt(CurrentMaxHealth * HealthRatio), 0, CurrentMaxHealth);
152→    }
153→    else
154→    {
155→        CurrentHealth = FMath::Clamp(CurrentHealth + Delta, 0, CurrentMaxHealth);
156→    }
157→    OnHealthChangedDelegate.Broadcast(CurrentHealth, CurrentMaxHealth);
158→}
