172→void ALFPTacticsUnit::BeginPlay()
173→{
174→    Super::BeginPlay();
175→
176→    if (!bStatsInitialized)
177→    {
178→        if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
179→        {
180→            InitializeFromRegistry(GI->UnitRegistry);
181→        }
182→        else
183→        {
184→            ResetCurrentStatsToBase();
185→        }
186→    }
187→
188→    // 注册到回合管理器
189→    if (ALFPTurnManager* TurnManager = GetTurnManager())
190→    {
191→        TurnManager->RegisterUnit(this);
192→    }
193→
194→    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
195→    {
196→        if (Condition)
197→        {
198→            Condition->RegisterCondition(this);
199→        }
200→    }
201→
202→    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
203→    SetCurrentCoordinates(SpawnPoint);
204→
205→	// 初始化血量
206→    CurrentHealth = FMath::Clamp(CurrentHealth, 0, GetCurrentMaxHealth());
207→	InitializeHealthBar();
208→
209→    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
210→
211→    // 如果是敌方单位，创建AI控制器
212→    if (IsEnemy())
213→    {
214→        FActorSpawnParameters SpawnParams;
215→        SpawnParams.Owner = this;
216→        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
217→
218→        if (AIControllerClass)
219→        {
220→            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
221→            if (AIController)
222→            {
223→                AIController->Possess(this);
224→                AIController->SetControlledUnit(this);
225→            }
226→        }
227→    }
228→}
